const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  //  extract AQI safely
  const aqiValue =
    aqi?.["us-epa-index"] ??
    aqi?.air_quality?.["us-epa-index"] ??
    aqi;

  const hasAQI = aqiValue !== undefined && aqiValue !== null;

  return (
    <div className="card">

  <h2>{city}</h2>

  <img src={icon} alt="weather" />

  <div className="temp">{temperature}</div>

  <div className="condition">{condition}</div>

  <div className="stats">
    <div className="stat-box">🌡️{feelsLike}</div>
    <div className="stat-box">💨{wind}</div>
    <div className="stat-box">💧{humidity}</div>
  </div>

  <div className="aqi-badge">
     {aqi}
  </div>
  
</div>

  );
};

export default WeatherCard;
